plugin.detectCode:
const t = input.trim().toLowerCase();
// Short query words, likely an emoji search
const words = t.split(/\s+/);
return words.length <= 5 && words.every(w => /^[a-z]+$/.test(w)) && t.length < 60 ? 0.6 : 0;

