const EMOJIS = [
  ['😀','grinning face','smile happy grin'],['😂','face with tears of joy','laugh funny lol'],['🥰','smiling face with hearts','love heart adore'],['😎','smiling face with sunglasses','cool sunglasses'],['🤔','thinking face','think ponder hmm'],['😢','crying face','sad cry tear'],['😡','enraged face','angry mad rage'],['🎉','party popper','party celebrate confetti'],['🔥','fire','fire hot flame burn'],['💡','light bulb','idea light bulb'],['✅','check mark button','check done ok yes'],['❌','cross mark','no cancel wrong error'],['⚠️','warning','warning caution alert'],['🚀','rocket','rocket launch space fast'],['🐛','bug','bug insect error debug'],['🔒','locked','lock security private'],['🔓','unlocked','unlock open'],['📝','memo','note write document'],['📊','bar chart','chart graph data analytics'],['📅','calendar','calendar date schedule'],['⏰','alarm clock','time alarm clock'],['🔍','magnifying glass tilted left','search find look'],['💬','speech bubble','comment chat message talk'],['📧','e-mail','email mail message'],['📁','file folder','folder directory files'],['🌐','globe with meridians','web internet global'],['💻','laptop','computer laptop code'],['📱','mobile phone','phone mobile smartphone'],['🖥️','desktop computer','desktop pc monitor'],['⌨️','keyboard','keyboard type input'],['🖱️','computer mouse','mouse click cursor'],['📦','package','package box shipping'],['🏠','house','home house'],['🏢','office building','office building work'],['🌟','glowing star','star featured important'],['❤️','red heart','love heart'],['💯','hundred points','100 percent perfect'],['👍','thumbs up','like good approve ok'],['👎','thumbs down','dislike bad'],['🙏','folded hands','please thanks pray'],['💪','flexed biceps','strong muscle power'],['🎯','direct hit','target goal bullseye'],['🧠','brain','brain smart think intelligence'],['👀','eyes','look see watch'],['💀','skull','dead skull danger'],['🤖','robot','robot bot ai machine'],['🦄','unicorn','unicorn special magic'],['🐍','snake','snake python'],['🦊','fox','fox clever'],['🌈','rainbow','rainbow color colorful'],
];

const query = input.trim().toLowerCase();
const results = EMOJIS.filter(([emoji, name, tags]) =>
  name.includes(query) || tags.includes(query) || query.split(/\s+/).some(w => name.includes(w) || tags.includes(w))
);

if (results.length === 0) return { output: `No emojis found for "${query}"`, outputLanguage: 'text' };

const lines = results.map(([emoji, name]) => {
  const cp = [...emoji].map(c => 'U+' + c.codePointAt(0).toString(16).toUpperCase().padStart(4,'0')).join(' ');
  return `${emoji}  ${name.padEnd(35)} ${cp}`;
});
return { output: lines.join('\n'), outputLanguage: 'text' };
